#### 父类在初始化列表中初始化

```c++
#include 
using namespace std;

class base
{
private:
    int a, b;
public:
    base(int a1, int b1) : a(a1), b(b1) {}
    ~base() {}
};

class derived : public base
{
private:
    int x, y;
public:
    // 基类构造写在初始化列表！
    derived(int a1, int b1, int x1, int y1) : base(a1, b1)
    {
        x = x1;
        y = y1;
    }
    ~derived() {}
};  // 类结束必须加分号

int main()
{
    derived d(1, 2, 3, 4);
    return 0;
}
```

