        // 获取当前正在写入的缓冲区
        if(hdma_usart1_rx.Instance->CR & DMA_SxCR_CT)
        {
            // CT=1 当前DMA写buf1，buf0已经收完整包
            rx_ready = 1;
        }
        else
        {
            // CT=0 当前DMA写buf0，buf1已经收完整包
            rx_ready = 2;
        }
        // 清除空闲中断标志
        __HAL_UART_CLEAR_IDLEFLAG(&huart1);
    }
}

