WWDG 计数到`0x40`会进**提前唤醒回调**，此时还没复位，是唯一能抢救现场的时机；

普通 RAM 重启会清空，所以用**后备 SRAM（BKPSRAM）** 存故障信息，断电才清空，重启后可读；

制造卡死（取消`while(1);`注释）

1. 程序进入死循环，再也不会执行喂狗；
2. WWDG 计数器持续递减，降到`0x40`；
3. 触发提前唤醒中断，进入`HAL_WWDG_EarlyWakeupCallback`；
4. 执行`WriteFaultLog`，把**故障类型、卡死时间、堆栈地址**存入后备 SRAM；
5. 回调不喂狗，计数器继续降到`0x3F`，芯片自动复位重启。

### 一阶卡尔曼滤波

```c
// 一维卡尔曼滤波（最精简版，严格5个公式）
typedef struct {
    float x_hat;  // 估计状态
    float P;      // 估计误差协方差
    float A;      // 状态转移
    float H;      // 观测矩阵
    float Q;      // 过程噪声
    float R;      // 观测噪声
} Kalman1D;

// 卡尔曼滤波：输入观测值 z，输出最优估计
float Kalman1D_Update(Kalman1D *k, float z)
{
    // 1. 预测状态
    float x_pre = k->A * k->x_hat;

    // 2. 预测协方差
    float P_pre = k->A * k->P * k->A + k->Q;

    // 3. 卡尔曼增益（核心）
    float K = P_pre * k->H / (k->H * P_pre * k->H + k->R);

    // 4. 更新状态（融合观测）
    k->x_hat = x_pre + K * (z - k->H * x_pre);

    // 5. 更新协方差（最后一步）
    k->P = (1 - K * k->H) * P_pre;

    return k->x_hat;
}

// 初始化例子
Kalman1D kf;

void Kalman_Init(void)
{
    kf.x_hat = 0;    // 初始状态
    kf.P    = 1;     // 初始协方差
    kf.A    = 1;     // 一维恒值模型（最常用）
    kf.H    = 1;     // 观测矩阵
    kf.Q    = 0.01f; // 过程噪声（越小越信任模型）
    kf.R    = 0.1f;  // 观测噪声（越小越信任传感器）
}

```

### 二阶卡尔曼滤波

```c
typedef struct
{
    // 状态向量 [位置, 速度]
    float pos;   // 位置估计 x1
    float vel;   // 速度估计 x2

    // 误差协方差矩阵 P 2×2
    float P11, P12;
    float P21, P22;

    // 系统参数
    float dt;    // 采样时间
    float Q;     // 过程噪声(加速度噪声)
    float R;     // 观测噪声(位置测量噪声)
} Kalman2D;

// 初始化二维卡尔曼 位置+速度
void Kalman2D_Init(Kalman2D *kf, float dt)
{
    kf->dt = dt;

    // 初始状态
    kf->pos = 0.0f;
    kf->vel = 0.0f;

    // 初始协方差 P
    kf->P11 = 1.0f;  kf->P12 = 0.0f;
    kf->P21 = 0.0f;  kf->P22 = 1.0f;

    // 噪声调参
    kf->Q = 0.05f;
    kf->R = 0.2f;
}

// z：当前位置观测值
void Kalman2D_Update(Kalman2D *kf, float z)
{
    float dt = kf->dt;
    float Q  = kf->Q;
    float R  = kf->R;

    // ========== 1. 状态预测（第1公式）==========
    float pos_pre = kf->pos + kf->vel * dt;
    float vel_pre = kf->vel;

// ========== 2. 协方差预测（第2公式）==========
    float p11_pre = kf->P11 + kf->P12*dt + (kf->P21 + kf->P22*dt)*dt + 0.5f*0.5f*dt*dt*dt*dt*Q;
    float p12_pre = kf->P12 + kf->P22*dt + 0.5f*dt*dt*dt*Q;
    float p21_pre = p12_pre;
    float p22_pre = kf->P22 + dt*dt*Q;

    // ========== 3. 卡尔曼增益（第3公式）==========
    float S = p11_pre + R;
    float K1 = p11_pre / S;
    float K2 = p21_pre / S;

    // ========== 4. 状态更新（第4公式）==========
    float residual = z - pos_pre;
    kf->pos = pos_pre + K1 * residual;
    kf->vel = vel_pre + K2 * residual;

    // ========== 5. 协方差更新（第5公式）==========
    kf->P11 = (1 - K1) * p11_pre;
    kf->P12 = (1 - K1) * p12_pre;
    kf->P21 = (1 - K2) * p21_pre;
    kf->P22 = (1 - K2) * p22_pre;
}

// 1. 定义变量
Kalman2D kf;

// 2. 初始化 采样周期0.1s
Kalman2D_Init(&kf, 0.1f);

// 3. 每周期调用一次
float measure_pos = 20.5f;   // 传感器读到的位置
Kalman2D_Update(&kf, measure_pos);

// 输出滤波结果
float filter_pos = kf.pos;
float filter_vel = kf.vel;
```

